cssRequirements.css:
@layer priority1 {
  .basex-tooltip-popup {
    opacity: 1;
    transform: scale(1);
    transition:
      opacity 150ms ease-out,
      transform 150ms ease-out;
  }
  .basex-tooltip-popup[data-starting-style],
  .basex-tooltip-popup[data-ending-style] {
    opacity: 0;
    transform: scale(0.95);
  }
  @media (prefers-reduced-motion: reduce) {
    .basex-tooltip-popup {
      transition: none;
    }
    .basex-tooltip-popup[data-starting-style],
    .basex-tooltip-popup[data-ending-style] {
      opacity: 1;
      transform: none;
    }
  }
}
